import React, { useState, useEffect } from "react";
import "./HomePage.css";
import Main from "../../Components/Main/Main";
import Home from "../../Components/Home/Home";
import { ProductsData } from "../../Data/ProductsData";
import { HomeSlider } from "../../Data/SliderImages";
import Loading from "../Loading/Loading"; // Import Loading component

function HomePage() {
  const [isLoading, setIsLoading] = useState(true); // State to track loading
  const [isHomeSliderLoaded, setIsHomeSliderLoaded] = useState(false); // Track HomeSlider images loading state
  const [isProductsLoaded, setIsProductsLoaded] = useState(false); // Track ProductsData images loading state

  useEffect(() => {
    window.scrollTo(0, 0);
  }, []);

  // Function to check if all images in HomeSlider are loaded
  const checkSliderImages = () => {
    let totalImages = HomeSlider.length;
    let loadedImages = 0;

    HomeSlider.forEach((imgSrc) => {
      const img = new Image();
      img.src = imgSrc;
      img.onload = () => {
        loadedImages++;
        if (loadedImages === totalImages) {
          setIsHomeSliderLoaded(true);
        }
      };
    });
  };

  // Function to check if all images in ProductsData are loaded
  const checkProductImages = () => {
    let totalImages = ProductsData.length;
    let loadedImages = 0;

    ProductsData.forEach((product) => {
      product.images.forEach((imgSrc) => {
        const img = new Image();
        img.src = imgSrc;
        img.onload = () => {
          loadedImages++;
          if (loadedImages === totalImages * 3) { // Assuming each product has 3 images
            setIsProductsLoaded(true);
          }
        };
      });
    });
  };

  // Initialize image loading checks when the page loads
  useEffect(() => {
    checkSliderImages();
    checkProductImages();
  }, []);

  // If any images are not loaded yet, show the loading screen
  useEffect(() => {
    if (isHomeSliderLoaded && isProductsLoaded) {
      setIsLoading(false); // All images are loaded
    }
  }, [isHomeSliderLoaded, isProductsLoaded]);

  if (isLoading) {
    return <Loading />; // Show loading screen until images are loaded
  }

  return (
    <div className="background">
      <Home slides={HomeSlider} />
      <Main images={ProductsData} />
    </div>
  );
}

export default HomePage;
